'use client'

import React from 'react'
import Link from 'next/link'
import Reveal from '../components/Reveal'
import AnimatedIllustrations from '../components/AnimatedIllustrations'

const ServiceDetail = ({ service }) => {
    if (!service) return null;

    return (
        <main className="relative min-h-screen bg-[#0a0f15]" style={{ background: 'linear-gradient(135deg, #11181f 0%, #0d1117 100%)' }}>
            <AnimatedIllustrations />

            {/* Hero Section */}
            <section className="relative pt-32 pb-20 lg:pt-40 lg:pb-28">
                <div className="container mx-auto px-4">
                    <div className="max-w-4xl mx-auto text-center">
                        <Reveal>
                            <Link
                                href="/services"
                                className="inline-flex items-center gap-2 text-[#f7e839] hover:text-white transition-colors mb-8 font-medium bg-white/5 px-4 py-2 rounded-full border border-white/10"
                            >
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                                    <path d="M19 12H5m7 7l-7-7 7-7" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                </svg>
                                Back to All Services
                            </Link>
                        </Reveal>
                        <Reveal>
                            <h1 className="text-4xl md:text-5xl lg:text-6xl font-extrabold text-white mb-6 tracking-tight">
                                {service.t}
                            </h1>
                        </Reveal>
                        <Reveal>
                            <p className="text-xl md:text-2xl text-white/80 leading-relaxed max-w-3xl mx-auto">
                                {service.d}
                            </p>
                        </Reveal>
                    </div>
                </div>
            </section>

            {/* Featured Image */}
            <section className="relative pb-16">
                <div className="container mx-auto px-4">
                    <Reveal>
                        <div className="max-w-5xl mx-auto relative rounded-3xl overflow-hidden shadow-2xl border border-white/10">
                            <div className="absolute inset-0 bg-gradient-to-t from-[#0a0f15] via-transparent to-transparent z-10"></div>
                            <img
                                src={service.img}
                                alt={service.t}
                                className="w-full h-[400px] md:h-[600px] object-cover"
                            />
                        </div>
                    </Reveal>
                </div>
            </section>

            {/* Service Content */}
            <section className="relative py-16">
                <div className="container mx-auto px-4">
                    <div className="max-w-4xl mx-auto">
                        {service.subServices && service.subServices.length > 0 ? (
                            <div className="space-y-12">
                                <Reveal>
                                    <div className="text-center mb-16">
                                        <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">Explore Our Strategic <span className="text-[#f7e839]">Solutions</span></h2>
                                        <p className="text-white/60 text-lg">We provide a comprehensive suite of targeted digital solutions designed to scale your brand.</p>
                                    </div>
                                </Reveal>

                                <div className="grid md:grid-cols-2 gap-6">
                                    {service.subServices.map((sub, idx) => (
                                        <Reveal key={idx} as="div" className="bg-gradient-to-br from-white/5 to-white/10 border border-white/10 p-8 rounded-2xl hover:border-[#f7e839]/40 transition-all duration-300 hover:-translate-y-1">
                                            <h3 className="text-xl font-bold text-white mb-4 flex items-start gap-4">
                                                <span className="flex items-center justify-center w-8 h-8 rounded-lg bg-[#f7e839]/20 text-[#f7e839] text-sm shrink-0">
                                                    {idx + 1}
                                                </span>
                                                {sub.title}
                                            </h3>
                                            <p className="text-white/70 leading-relaxed mb-6">
                                                {sub.description}
                                            </p>

                                            {sub.subItems && (
                                                <div className="mt-auto pt-6 border-t border-white/10">
                                                    <h4 className="text-[#f7e839] text-sm font-semibold uppercase tracking-wider mb-2">Key Areas Focus</h4>
                                                    <p className="text-white/80">
                                                        {sub.subItems}
                                                    </p>
                                                </div>
                                            )}
                                        </Reveal>
                                    ))}
                                </div>
                            </div>
                        ) : (
                            <div className="bg-white/5 border border-white/10 rounded-2xl p-8 md:p-12">
                                <Reveal>
                                    <h2 className="text-3xl font-bold text-white mb-8 border-b border-white/10 pb-6">What's Included:</h2>
                                </Reveal>
                                <div className="space-y-6">
                                    {service.points.map((point, idx) => (
                                        <Reveal key={idx} as="div" className="flex items-start gap-4">
                                            <div className="h-8 w-8 rounded-full bg-[#f7e839]/20 flex items-center justify-center mt-1 flex-shrink-0">
                                                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                                                    <path d="M20 6L9 17l-5-5" stroke="#f7e839" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
                                                </svg>
                                            </div>
                                            <span className="text-white/80 text-xl leading-relaxed">{point}</span>
                                        </Reveal>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </section>

            {/* CTA Section */}
            <section className="py-20 bg-[#06060a]">
                <div className="container mx-auto px-4">
                    <Reveal>
                        <div className="bg-gradient-to-r from-[#1a1f26] to-[#2d3748] rounded-3xl p-12 md:p-16 text-center border border-white/10 shadow-2xl max-w-5xl mx-auto relative overflow-hidden">
                            <div className="absolute inset-0 bg-[url('/assets/images/noise.png')] opacity-20 mix-blend-overlay"></div>
                            <div className="relative z-10">
                                <h3 className="text-3xl md:text-5xl font-bold text-white mb-6">
                                    Ready to Start Your <span className="text-[#f7e839]">{service.t}</span> Project?
                                </h3>
                                <p className="text-white/80 text-lg md:text-xl mb-10 max-w-2xl mx-auto">
                                    Get in touch with our team today to discuss your objectives and receive a customized strategy tailored to your exact needs.
                                </p>
                                <a
                                    href="/contact"
                                    className="inline-flex items-center justify-center gap-3 px-10 py-4 text-lg rounded-xl bg-gradient-to-r from-[#f7e839] to-[#f5d428] text-[#11181f] font-bold hover:shadow-[0_0_30px_rgba(247,232,57,0.3)] transition-all duration-300 hover:-translate-y-1"
                                >
                                    Get Your Custom Proposal
                                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
                                        <path d="M5 12h14m-7-7l7 7-7 7" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
                                    </svg>
                                </a>
                            </div>
                        </div>
                    </Reveal>
                </div>
            </section>
        </main>
    );
};

export default ServiceDetail;
